function defaultRouteD({ px, py, chip }) {
  // Route connectors using a trace-like multi-bend pattern.
  // The goal is to visually match the PCB trace routing style:
  // horizontal/vertical legs with an intentional offset before reaching the chip.
  const dx = chip.px - px;
  const absDx = Math.abs(dx);

  // Side classification
  const isLeft = dx < 0;
  const isTop = py < chip.py;

  // Bias controls (tuned to the PCB wiring feel)
  const xBias1 = isLeft ? 0.28 : 0.72;
  const xBias2 = isLeft ? 0.18 : 0.82;
  const yLegTop = 0.30; // where the first vertical jog happens (as portion of distance)

  // First elbow X: move from node toward chip but keep a visible jog
  const midX1 = px + dx * xBias1;
  // Second elbow X: closer to chip, but not directly so the route has a bend
  const midX2 = px + dx * xBias2;

  // First vertical jog Y: depends on whether node is on top/bottom side
  const yJog = isTop ? py + (chip.py - py) * yLegTop : py - (py - chip.py) * yLegTop;

  // Build path with 4 legs (3 bends):
  // node -> (midX1, py) -> (midX1, yJog) -> (midX2, yJog) -> (midX2, chip.py) -> chip
  // We keep it all orthogonal to match the PCB traces.
  return `M ${px} ${py} L ${midX1} ${py} L ${midX1} ${yJog} L ${midX2} ${yJog} L ${midX2} ${chip.py} L ${chip.px} ${chip.py}`;
}


