// Simple helper: polyline points ([[x,y],...]) => SVG path d.
// Uses the same % coordinate system as the PCB overlay.
// Example: [[10,10],[20,10],[20,30]] => "M 10 10 L 20 10 L 20 30"
// (Kept near mapping so it’s easy to tweak.)
function polylineToD(points) {
  if (!points || points.length < 2) return "";
  return points
    .map((p, i) => {
      const [x, y] = p;
      return `${i === 0 ? "M" : "L"} ${x} ${y}`;
    })
    .join(" ");
}



