function PulseAnimation({ path }) {
  const [t, setT] = useState(0);
  const rafRef = useRef(null);
  const startRef = useRef(Date.now());
  const DURATION = 1400 + Math.random() * 600;

  useEffect(() => {
    function tick() {
      const elapsed = Date.now() - startRef.current;
      const progress = Math.min(elapsed / DURATION, 1);
      setT(progress);
      if (progress < 1) rafRef.current = requestAnimationFrame(tick);
    }
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  if (t >= 1) return null;

  // Interpolate position along multi-segment path
  const segments = [];
  let totalLen = 0;
  for (let i = 0; i < path.length - 1; i++) {
    const [x0,y0] = path[i], [x1,y1] = path[i+1];
    const len = Math.hypot(x1-x0, y1-y0);
    segments.push({ x0,y0,x1,y1,len });
    totalLen += len;
  }
  let rem = t * totalLen;
  let px = path[0][0], py = path[0][1];
  for (const seg of segments) {
    if (rem <= seg.len) {
      const f = rem / Math.max(seg.len, 0.001);
      px = seg.x0 + (seg.x1-seg.x0)*f;
      py = seg.y0 + (seg.y1-seg.y0)*f;
      break;
    }
    rem -= seg.len;
  }

  const opacity = t < 0.1 ? t/0.1 : t > 0.85 ? (1-t)/0.15 : 1;

  return (
    <g opacity={opacity} filter="url(#pulseGlow)">
      {/* Trail */}
      <circle cx={px} cy={py} r="0.9" fill="rgba(220,180,255,0.35)"/>
      {/* Core */}
      <circle cx={px} cy={py} r="0.45" fill="rgba(240,210,255,0.95)"/>
      {/* Glow halo */}
      <circle cx={px} cy={py} r="1.4" fill="none" stroke="rgba(185,120,255,0.25)" strokeWidth="0.3"/>
    </g>
  );
}

