function CircuitConnection({ feature, index, active }) {
  const [sx, sy] = feature.node;
  const cx = 500;
  const cy = 330;
  const controlA = [sx + (cx - sx) * 0.28, sy];
  const controlB = [sx + (cx - sx) * 0.62, cy + (sy < cy ? -38 : 38)];
  const d = `M ${sx} ${sy} C ${controlA[0]} ${controlA[1]}, ${controlB[0]} ${controlB[1]}, ${cx} ${cy}`;
  const delay = index * 0.22;

  return (
    <g>
      <path d={d} stroke="rgba(255,255,255,0.05)" strokeWidth="14" fill="none" strokeLinecap="round" />
      <path
        d={d}
        stroke="url(#idleTrace)"
        strokeWidth="3.2"
        fill="none"
        strokeLinecap="round"
        strokeDasharray="12 16"
        className="trace-idle"
        style={{ animationDelay: `${delay}s` }}
      />
      <motion.path
        d={d}
        stroke={active ? "url(#hotTrace)" : "rgba(34,211,238,0.28)"}
        strokeWidth={active ? 5 : 2}
        fill="none"
        strokeLinecap="round"
        filter={active ? "url(#traceGlow)" : "none"}
        initial={false}
        animate={{ opacity: active ? 1 : 0.36, pathLength: active ? [0.2, 1, 0.92] : 1 }}
        transition={{ duration: active ? 0.75 : 0.35, ease: "easeOut" }}
      />
      <circle r={active ? 6 : 3.2} fill={active ? "#ffffff" : "#67e8f9"} opacity={active ? 0.95 : 0.35} filter="url(#traceGlow)">
        <animateMotion dur={active ? "1.15s" : "6s"} begin={`${delay}s`} repeatCount="indefinite" path={d} />
      </circle>
      {active && (
        <circle r="3.6" fill="#22d3ee" filter="url(#traceGlow)">
          <animateMotion dur="0.72s" repeatCount="indefinite" path={d} />
        </circle>
      )}
    </g>
  );
}

